                                        if (temp_EMlst != null && temp_EMlst.Count > 0)
                                        {
                                            Numerator = Numerator + temp_EMlst.Count;
                                        }
                                    }
                                }
                            }
                        }
                    }

                    PQRIlst.Add(NumeratorandDenominatorCalculation(Denominator, Numerator, "0028"));
