                        IList<ulong> enc_id_lst = new List<ulong>();

                        for (int i = 0; i < denom_human_lst.Count; i++)
                        {

                            IList<ulong> temp_enc_id = (from doc in encounter_list
                                                        where doc.Human_ID == Convert.ToUInt32(denom_human_lst[i])
